var input = $input.first().json;
var articles = input.results || input.data || [];
if (!Array.isArray(articles)) articles = [];

// GDA target agencies and keywords
var targetKw = ['army','navy','air force','socom','cybercom','inscom','disa','mda','faa','cecom','tradoc','indopacom','cybersecurity','electronic warfare','intelligence','c5isr','seta','systems engineering','training','simulation','it modernization','cloud','ai','machine learning','software development'];
var targetNaics = ['541330','541511','541512','541513','541519','541611','541612','541613','541614','541618','541690','541715','611430'];

var relevant = articles.filter(function(a) {
  var text = ((a.name || '') + ' ' + (a.content_snippet || '') + ' ' + (a.govtribe_ai_summary || '')).toLowerCase();
  return targetKw.some(function(kw) { return text.includes(kw); });
});

if (relevant.length === 0) return [{json:{skip:true, reason:'no_relevant_ndaa_updates', checked:articles.length}}];

// Build context for AI analysis
var context = relevant.map(function(a) {
  return '## ' + (a.name || 'Untitled') + '\n' + (a.content_snippet || a.govtribe_ai_summary || 'No content') + '\nURL: ' + (a.govtribe_url || '');
}).join('\n\n');

return [{json:{relevant_count:relevant.length, total_checked:articles.length, context:context, articles:relevant}}];

var aiResp = $input.first().json;
var text = '';
if (aiResp.content && aiResp.content[0]) text = aiResp.content[0].text || '';
var provisions = [];
try {
  var jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) provisions = JSON.parse(jsonMatch[0]).provisions || [];
} catch(e) {}

var articles = $('Filter Relevant').first().json.articles || [];

// Build SQL to insert into intelligence log
var inserts = provisions.map(function(p) {
  var title = ('NDAA: ' + (p.title || 'Unknown')).replace(/'/g, "''").substring(0, 200);
  var body = (p.impact + ' | Action: ' + p.recommended_action + ' | Agencies: ' + (p.affected_agencies || []).join(', ')).replace(/'/g, "''").substring(0, 1000);
  var signal = p.opportunity_signal || 'neutral';
  var score = signal === 'positive' ? 90 : signal === 'negative' ? 70 : 50;
  return "INSERT INTO gda_intelligence_log (title, source, category, relevance_score, body, created_at) VALUES ('" + title + "', 'NDAA Auto-Ingest', 'legislative', " + score + ", '" + body + "', NOW())";
});

var sql = inserts.length > 0 ? inserts.join('; ') + ';' : 'SELECT 1;';

return [{json:{sql:sql, provision_count:provisions.length, provisions:provisions.slice(0,3)}}];
